__CPROVER_requires(__CPROVER_is_fresh(d_lengths, ZOPFLI_NUM_D * sizeof(*d_lengths)))
__CPROVER_requires(__CPROVER_forall { unsigned kl; (kl < ZOPFLI_NUM_LL) ==> ll_lengths[kl] == 1 })
