__CPROVER_ensures((lstart == lend) ==> (__CPROVER_return_value == 0))
/* Otherwise the byte range is the exact span from lstart to the end of lend-1. */
__CPROVER_ensures((lstart != lend) ==> (__CPROVER_return_value ==
